const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Default fallback queries if JSON parsing fails
  parsed = {
    queries: [
      {
        title: "Total post counts across sources",
        sql: "SELECT 'reddit' as src, count(*) from s_reddit.posts UNION SELECT 'substack', count(*) from s_substack.posts;"
      }
    ]
  };
}

const queries = Array.isArray(parsed.queries) ? parsed.queries : [];
return queries.map(q => ({ json: { title: q.title, sql: q.sql } }));

const items = $input.all();
const queryMeta = $('Parse Queries').all();

const results = items.map((item, index) => {
  const meta = queryMeta[index] ? queryMeta[index].json : { title: 'Unknown Query', sql: '' };
  return {
    title: meta.title,
    sql: meta.sql,
    data: item.json
  };
});

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/kowalski.md', 'utf8');
} catch (e) {
  persona = 'Kowalski, tactical and military-grade database analyst agent.';
}

return [{ json: { results, kowalski_persona: persona } }];
